svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var dataLayerEl = document.getElementById('data-layer');
    var legendRoot = document.getElementById('legend-root');
    var SERIES_REVEAL_DURATION = 0.8;
    var pointItems = [];
    var seriesGroups = [];

    var quarters = ["Q1 '22","Q2 '22","Q3 '22","Q4 '22","Q1 '23","Q2 '23","Q3 '23","Q4 '23"];
    var series = [
      { id: 1, name: 'North America', ci: 1, values: [1.0, 1.5, 2.5, 3.5, 4.75, 5.0, 5.25, 5.25] },
      { id: 2, name: 'Europe', ci: 2, values: [0.5, 0.5, 1.0, 2.0, 3.0, 3.5, 4.0, 4.25] },
      { id: 3, name: 'Asia-Pacific', ci: 3, values: [0.25, 0.5, 0.75, 1.25, 2.0, 2.5, 2.75, 3.0] }
    ];

    var plotL = 68;
    var plotR = 832;
    var plotT = 100;
    var plotB = 500;
    var n = quarters.length;
    var step = (plotR - plotL) / (n - 1);
    var yMin = 0;
    var yMax = 8;

    function xAt(i) { return plotL + i * step; }
    function yAt(v) { return plotB - (v - yMin) / (yMax - yMin) * (plotB - plotT); }
    function jumpPath(values) {
      var d = 'M' + xAt(0) + ',' + yAt(values[0]);
      for (var i = 1; i < values.length; i += 1) d += ' H' + xAt(i) + ' V' + yAt(values[i]);
      return d;
    }
    function nearestIdx(mx) {
      return Math.max(0, Math.min(n - 1, Math.round((mx - plotL) / step)));
    }
    function svgMouseX(event) {
      var pt = svg.createSVGPoint();
      pt.x = event.clientX;
      pt.y = event.clientY;
      return pt.matrixTransform(svg.getScreenCTM().inverse()).x;
    }

    series.forEach(function (entry, seriesIndex) {
      var sg = ctx.el('g', {
        id: 'sg-' + entry.id,
        'class': 'sg',
        'data-series-id': String(entry.id),
        'data-series-index': String(seriesIndex)
      });
      var path = ctx.el('path', {
        'class': 'series-path series-' + entry.ci + ' use-series-stroke',
        d: jumpPath(entry.values)
      });
      var hitPath = ctx.el('path', {
        'class': 'series-hit',
        d: jumpPath(entry.values)
      });

      sg.appendChild(hitPath);
      sg.appendChild(path);

      entry.values.forEach(function (value, pointIndex) {
        var cx = xAt(pointIndex);
        var cy = yAt(value);
        var dotGroup = ctx.el('g', {
          'class': 'dot-g',
          'data-series-index': String(seriesIndex),
          'data-point-index': String(pointIndex)
        });
        var dotRing = ctx.el('circle', {
          cx: cx,
          cy: cy,
          r: 5,
          'class': 'dot-circle series-' + entry.ci + ' use-series-stroke'
        });
        var dotCore = ctx.el('circle', {
          cx: cx,
          cy: cy,
          r: 3,
          'class': 'series-' + entry.ci
        });
        var hit = ctx.el('circle', {
          cx: cx,
          cy: cy,
          r: 12,
          'class': 'dot-hit',
          'data-value': value.toFixed(2) + '%',
          'data-label': quarters[pointIndex],
          'data-meta': entry.name,
          'data-series-id': String(entry.id),
          'data-point-index': String(pointIndex),
          'data-item-cx': String(cx),
          'data-item-top': String(cy)
        });

        dotGroup.appendChild(dotRing);
        dotGroup.appendChild(dotCore);
        sg.appendChild(dotGroup);
        sg.appendChild(hit);
        hit._dotGroup = dotGroup;
        pointItems.push(hit);
      });

      hitPath.addEventListener('mouseenter', function (event) {
        var idx = nearestIdx(svgMouseX(event));
        var hit = sg.querySelector('.dot-hit[data-point-index="' + idx + '"]');
        if (hit) hit.dispatchEvent(new Event('mouseenter', { bubbles: true }));
      });
      hitPath.addEventListener('mousemove', function (event) {
        var idx = nearestIdx(svgMouseX(event));
        var hit = sg.querySelector('.dot-hit[data-point-index="' + idx + '"]');
        if (hit) hit.dispatchEvent(new Event('mouseenter', { bubbles: true }));
      });

      dataLayerEl.appendChild(sg);
      seriesGroups.push(sg);
    });

    ctx.initStandardLegend({
      legendEl: legendRoot,
      title: 'SERIES',
      labelMaxWidth: 118,
      items: series.map(function (entry) {
        return {
          label: entry.name,
          value: entry.values[entry.values.length - 1].toFixed(2) + '%',
          cls: 'series-' + entry.ci
        };
      })
    });

    ctx.initRevealSequence(seriesGroups, {
      animationName: 'fadeIn',
      duration: SERIES_REVEAL_DURATION,
      easing: 'ease-out',
      delays: seriesGroups.map(function (_, index) {
        return ctx.getStaggerDelay(index, seriesGroups.length, 1.0);
      })
    });

    var seriesHover = ctx.initSeriesHoverController({
      hoverLayer: dataLayerEl,
      seriesIds: series.map(function (entry) { return entry.id; }),
      pointCount: n,
      lineSelector: '#sg-{id}'
    });

    ctx.initStandardTooltip(dataLayerEl, pointItems, {
      tip: document.getElementById('tip'),
      plotL: 68,
      plotR: 832,
      plotT: 100,
      plotB: 500,
      placement: 'side',
      minWidth: 220,
      paddingX: 20,
      paddingY: 18,
      lineHeights: [42, 32, 32],
      trackPointer: false,
      getAnchor: function (itemEl) {
        return {
          x: Number(itemEl.getAttribute('data-item-cx')) || 0,
          y: Number(itemEl.getAttribute('data-item-top')) || 0
        };
      },
      getContent: function (itemEl) {
        return {
          primary: itemEl.getAttribute('data-value') || '',
          label: itemEl.getAttribute('data-label') || '',
          meta: itemEl.getAttribute('data-meta') || ''
        };
      },
      onActivate: function (itemEl) {
        seriesHover.activate(itemEl);
      },
      onDeactivate: function () {
        seriesHover.clear();
      },
      leaveTarget: dataLayerEl
    });

    ctx.markReadyAfterReveal(dataLayerEl, {
      delays: seriesGroups.map(function (_, index) {
        return ctx.getStaggerDelay(index, seriesGroups.length, 1.0);
      }),
      duration: SERIES_REVEAL_DURATION,
      buffer: 0.1
    });
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
